1	package merge
2	
3	import (
4		"crypto/sha256"
5		"encoding/hex"
6		"fmt"
7		"strings"
8	)
9	
10	// markerOpen is the literal opener every agent-sync marker shares. A body
11	// containing it means a caller passed pre-wrapped content (the engine
12	// owns markers) — rejected loudly so a Unit 13 double-wrap mistake
13	// fails in tests, not in production.
14	const markerOpen = "<!-- agent-sync:"
15	
16	// mergeMarkdown upserts or removes the agent-sync managed section for the
17	// entry's id. It owns the begin/end markers (KTD 5): the caller passes
18	// the INNER body. Recovery is refuse-don't-guess — any malformed marker
19	// state returns ErrMalformedManagedSection naming the line, with no
20	// write. Returns the merged bytes, the slice hash, and an optional
21	// warning (set when an indented marker for a non-target id is treated
22	// as user content).
23	func mergeMarkdown(existing []byte, e MergeEntry) (result []byte, sliceHash, warning string, err error) {
24		id, err := entryID(e)
25		if err != nil {
26			return nil, "", "", err
27		}
28		if !e.Remove && strings.Contains(string(e.Content), markerOpen) {
29			return nil, "", "", fmt.Errorf("merge: markdown body contains agent-sync marker %q (the engine owns markers; pass inner body only)", markerOpen)
30		}
31	
32		nl := detectNewline(existing)
33		lines := splitLinesKeepEnding(existing)
34	
35		pair, warn, perr := scanMarkers(lines, id)
36		if perr != nil {
37			return nil, "", "", perr
38		}
39	
40		if e.Remove {
41			if pair.found {
42				lines = append(lines[:pair.begin], lines[pair.end+1:]...)
43			}
44			return joinLines(lines), "", warn, nil
45		}
46	
47		block := renderManagedBlock(id, e.Source, e.Content, nl)
48		blockLines := splitLinesKeepEnding([]byte(block))
49		sum := sha256.Sum256([]byte(block))
50		sliceHash = hex.EncodeToString(sum[:])
51	
52		if pair.found {
53			tail := append([]string{}, lines[pair.end+1:]...)
54			lines = append(lines[:pair.begin], blockLines...)
55			lines = append(lines, tail...)
56			return joinLines(lines), sliceHash, warn, nil
57		}
58	
59		// Append a new section at EOF (with a top-of-file header for a new file).
60		if len(strings.TrimSpace(string(existing))) == 0 {
61			header := "<!-- Partially managed by agent-sync — edit outside the agent-sync:begin / agent-sync:end markers only. -->" + nl + nl
62			return []byte(header + block), sliceHash, warn, nil
63		}
64		if n := len(lines); n > 0 && !strings.HasSuffix(lines[n-1], "\n") {
65			lines[n-1] += nl
66		}
67		lines = append(lines, nl) // one blank separator before the appended section
68		lines = append(lines, blockLines...)
69		return joinLines(lines), sliceHash, warn, nil
70	}
71	
72	type markerPair struct {
73		found      bool
74		begin, end int // inclusive line indices of the begin/end marker lines
75	}
76	
77	// scanMarkers walks the lines applying the recovery state machine for
78	// the target id. It returns the matched pair (if any), a warning, or an
79	// ErrMalformedManagedSection on any bad marker state.
80	func scanMarkers(lines []string, targetID string) (markerPair, string, error) {
81		var pair markerPair
82		openID := ""
83		openLine := -1
84		seen := map[string]bool{}
85		warning := ""
86	
87		for i, raw := range lines {
88			core := strings.TrimRight(raw, "\r\n")
89			trimmed := strings.TrimLeft(core, " \t")
90			indented := trimmed != core
91	
92			bid, _, isBegin := parseBeginMarker(trimmed)
93			eid, isEnd := parseEndMarker(trimmed)
94			if !isBegin && !isEnd {
95				continue
96			}
97	
98			if indented {
99				// An indented marker is user content, EXCEPT an indented copy
100				// of the id we manage — that signals a re-indented managed
101				// section and silently appending a duplicate would grow stale
102				// copies, so refuse.
103				mid := bid
104				if isEnd {
105					mid = eid
106				}
107				if mid == targetID {
108					return markerPair{}, "", fmt.Errorf("%w: indented marker for managed id %q at line %d", ErrMalformedManagedSection, targetID, i+1)
109				}
110				warning = fmt.Sprintf("indented agent-sync marker at line %d treated as user content", i+1)
111				continue
112			}
113	
114			switch {
115			case isBegin:
116				if openLine >= 0 {
117					return markerPair{}, "", fmt.Errorf("%w: nested begin (id %q) at line %d before end of id %q", ErrMalformedManagedSection, bid, i+1, openID)
118				}
119				if seen[bid] {
120					return markerPair{}, "", fmt.Errorf("%w: duplicate begin id %q at line %d", ErrMalformedManagedSection, bid, i+1)
121				}
122				openID, openLine = bid, i
123			case isEnd:
124				if openLine < 0 {
