1	package merge
2	
3	import (
4		"bytes"
5		"crypto/sha256"
6		"encoding/hex"
7		"encoding/json"
8		"fmt"
9		"strings"
10	
11		"github.com/tidwall/gjson"
12		"github.com/tidwall/sjson"
13	)
14	
15	// mergeJSON upserts or removes the agent-sync entry at the entry's
16	// JSON-pointer locator inside existing, preserving user keys, ordering,
17	// and formatting. It strict-validates existing first; an unparseable
18	// file or a non-object parent is ErrMalformedToolOwnedFile (we never
19	// rewrite a file we cannot parse). Returns the merged bytes and the
20	// SHA-256 of the rendered agent-sync slice (empty on remove).
21	func mergeJSON(existing []byte, e MergeEntry) (result []byte, sliceHash string, err error) {
22		if _, err := entryID(e); err != nil {
23			return nil, "", err
24		}
25	
26		base := existing
27		if isBlank(base) {
28			base = []byte("{}")
29		} else if !json.Valid(base) {
30			return nil, "", fmt.Errorf("%w: not valid JSON", ErrMalformedToolOwnedFile)
31		}
32	
33		path, err := pointerToSjsonPath(e.Locator)
34		if err != nil {
35			return nil, "", err
36		}
37		parentPath := parentSjsonPath(path)
38	
39		// The parent (e.g. mcpServers), if present, must be an object — we
40		// will not set a key under an array/scalar.
41		if parentPath != "" {
42			if parent := gjson.GetBytes(base, parentPath); parent.Exists() && !parent.IsObject() {
43				return nil, "", fmt.Errorf("%w: %q is not a JSON object", ErrMalformedToolOwnedFile, parentPath)
44			}
45			// Reject a pre-existing duplicate of the agent-sync key under the
46			// parent (raw duplicate keys = ledger drift; JSON semantics make
47			// them degenerate so refuse rather than silently last-wins).
48			if dupCount(base, parentPath, lastSegment(path)) > 1 {
49				return nil, "", fmt.Errorf("%w: duplicate key %q under %q", ErrMalformedToolOwnedFile, lastSegment(path), parentPath)
50			}
51		}
52	
53		hadTrailingNewline := bytes.HasSuffix(existing, []byte("\n"))
54	
55		if e.Remove {
56			result, err = sjson.DeleteBytes(base, path)
57			if err != nil {
58				return nil, "", fmt.Errorf("merge: json delete %q: %w", path, err)
59			}
60			sliceHash = ""
61		} else {
62			if !json.Valid(e.Content) {
63				return nil, "", fmt.Errorf("%w: entry content is not a valid JSON value", ErrMalformedToolOwnedFile)
64			}
65			result, err = sjson.SetRawBytes(base, path, e.Content)
66			if err != nil {
67				return nil, "", fmt.Errorf("merge: json set %q: %w", path, err)
68			}
69			sum := sha256.Sum256([]byte(gjson.GetBytes(result, path).Raw))
70			sliceHash = hex.EncodeToString(sum[:])
71		}
72	
73		// Preserve trailing-newline convention of the input.
74		resultHasNewline := bytes.HasSuffix(result, []byte("\n"))
75		switch {
76		case hadTrailingNewline && !resultHasNewline:
77			result = append(result, '\n')
78		case !hadTrailingNewline && resultHasNewline:
79			result = bytes.TrimRight(result, "\n")
80		}
81		return result, sliceHash, nil
82	}
83	
84	// pointerToSjsonPath converts a JSON pointer (/mcpServers/agentsync_foo)
85	// to an sjson dot path (mcpServers.agentsync_foo), escaping sjson-special
86	// characters (. * ? \) in each segment so a key that contains them is
87	// treated literally.
88	func pointerToSjsonPath(pointer string) (string, error) {
89		if !strings.HasPrefix(pointer, "/") {
90			return "", fmt.Errorf("merge: json-pointer must start with '/': %q", pointer)
91		}
92		segs := strings.Split(pointer[1:], "/")
93		for i, s := range segs {
94			if s == "" {
95				return "", fmt.Errorf("merge: empty segment in json-pointer %q", pointer)
