		t.Fatalf("validate reported drift on an in-sync workspace: %+v", plan.Targets)
	}
	for _, tc := range plan.Targets {
		if len(tc.WouldUpdate) != 0 || len(tc.WouldCreate) != 0 || len(tc.OutOfBand) != 0 {
