	if len(data) == 0 {
		t.Fatal("rule file is empty")
	}

	// The ledger recorded the emitted path.
	root, err := fsroot.OpenWorkspaceRoot(ws)
	if err != nil {
		t.Fatalf("reopen root: %v", err)
