	led, err := ledger.Load(root, "claude")
	if err != nil {
		t.Fatalf("ledger.Load: %v", err)
	}
	found := false
	for _, e := range led.Entries {
		if e.Path == ".claude/rules/agent-sync/no-fri.md" {
			found = true
			if e.SHA256 == "" {
				t.Fatal("ledger entry missing sha256")
			}
