func TestSync_RemovedNodeOrphansItsFile(t *testing.T) {
	twoNodes := []ir.Node{
		{ID: "no-fri", Kind: ir.KindRule, Version: 1, Body: []byte("No PRs on Friday.")},
		{ID: "use-go", Kind: ir.KindRule, Version: 1, Body: []byte("Prefer Go.")},
